// Normalisiere + validiere rohen Lead. Domain ist Pflicht fuer Enrichment.
const out = [];
for (const item of $input.all()) {
  const b = item.json.body ?? item.json; // Webhook legt Payload unter .body ab
  const rawDomain = (b.domain || b.website || '').toString().trim().toLowerCase();
  // Domain aus E-Mail ableiten falls fehlend
  let domain = rawDomain.replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0];
  if (!domain && b.email && b.email.includes('@')) {
    domain = b.email.split('@')[1].trim().toLowerCase();
  }
  const freemail = ['gmail.com','gmx.de','web.de','yahoo.com','hotmail.com','outlook.com','t-online.de','icloud.com'];
  const valid = !!domain && domain.includes('.') && !freemail.includes(domain);
  out.push({
    json: {
      leadName: (b.name || b.fullName || '').toString().trim(),
      company: (b.company || b.companyName || '').toString().trim(),
      domain,
      email: (b.email || '').toString().trim().toLowerCase(),
      source: (b.source || 'webhook').toString(),
      receivedAt: new Date().toISOString(),
      isValid: valid,
      validationReason: valid ? 'ok' : (!domain ? 'no_domain' : (freemail.includes(domain) ? 'freemail_domain' : 'malformed_domain')),
      config: $('Set: Enrichment-Konfiguration').first().json
    }
  });
}
return out;

// Baue ein flaches, robustes Enrichment-Profil aus beiden API-Antworten.
// API-Antworten koennen je nach Provider verschachtelt/leer sein -> defensiv lesen.
const lead = $('Code: Lead normalisieren').item.json;
const all = $input.all();
const pick = (...vals) => vals.find(v => v !== undefined && v !== null && v !== '') ?? null;

// Merge-by-position liefert beide API-Objekte im selben item (combineByPosition)
const j = all[0]?.json ?? {};
// Firmendaten koennen unter j, j.company, j.data, j.result liegen
const c = j.company ?? j.data ?? j.result ?? j;
const s = j.socials ?? j.social ?? j;

const profile = {
  ...lead,
  enrichment: {
    legalName: pick(c.name, c.legalName, c.companyName),
    industry: pick(c.industry, c.sector, c.category),
    employees: pick(c.employees, c.employeeCount, c.size, c.headcount),
    revenue: pick(c.revenue, c.annualRevenue, c.estimatedRevenue),
    country: pick(c.country, c.location?.country, c.geo?.country),
    city: pick(c.city, c.location?.city),
    founded: pick(c.founded, c.foundedYear),
    techStack: pick(c.tech, c.technologies, c.techStack) || [],
    linkedin: pick(s.linkedin, s.linkedinUrl, c.linkedin, j.linkedin),
    twitter: pick(s.twitter, s.twitterUrl, c.twitter),
    facebook: pick(s.facebook, c.facebook),
    description: pick(c.description, c.summary, c.about)
  }
};
profile.enrichmentCompleteness = Object.values(profile.enrichment).filter(v => v && (Array.isArray(v) ? v.length : true)).length;
return [{ json: profile }];

parameters.text:
=Bewerte diesen angereicherten Lead gegen das ICP. Antworte AUSSCHLIESSLICH mit gueltigem JSON, keine Erklaerung davor/danach.

ICP-Definition:
{{ $json.config.icpDefinition }}

Lead-Profil:
Firma: {{ $json.enrichment.legalName || $json.company }}
Domain: {{ $json.domain }}
Branche: {{ $json.enrichment.industry }}
Mitarbeiter: {{ $json.enrichment.employees }}
Umsatz: {{ $json.enrichment.revenue }}
Land: {{ $json.enrichment.country }}
Tech-Stack: {{ JSON.stringify($json.enrichment.techStack) }}
Beschreibung: {{ $json.enrichment.description }}

Regeln:
- icpScore: Ganzzahl 0-100 (Fit mit ICP)
- tier: "A" (>=85), "B" (70-84), "C" (50-69), "D" (<50)
- reasons: Array mit max 3 kurzen Begruendungen (Fakten aus Profil, NICHTS erfinden)
- disqualified: true/false (harte Ausschlusskriterien aus ICP getroffen?)
- Wenn Daten fehlen: konservativ bewerten, im Feld dataGaps benennen

Antwortformat (exakt):
{"icpScore": <int>, "tier": "<A|B|C|D>", "disqualified": <bool>, "reasons": ["..."], "dataGaps": ["..."]}

parameters.jsCode:
// Parse LLM-JSON robust + merge mit Enrichment-Profil. Niemals throw -> Fallback-Score.
const profile = $('Code: Enrichment-Profil bauen').item.json;
const raw = $input.first().json;
const text = raw.output ?? raw.text ?? raw.response ?? JSON.stringify(raw);

let parsed = { icpScore: 0, tier: 'D', disqualified: false, reasons: ['llm_parse_failed'], dataGaps: ['scoring_unavailable'] };
try {
  const match = (typeof text === 'string' ? text : JSON.stringify(text)).match(/\{[\s\S]*\}/);
  if (match) parsed = { ...parsed, ...JSON.parse(match[0]) };
} catch (e) {
  parsed.reasons = ['llm_parse_error: ' + e.message];
}
const score = Math.max(0, Math.min(100, parseInt(parsed.icpScore, 10) || 0));
const threshold = profile.config.scoreThreshold ?? 70;
return [{
  json: {
    leadName: profile.leadName,
    company: profile.enrichment.legalName || profile.company,
    domain: profile.domain,
    email: profile.email,
    source: profile.source,
    enrichment: profile.enrichment,
    enrichmentCompleteness: profile.enrichmentCompleteness,
    icpScore: score,
    tier: parsed.tier,
    disqualified: !!parsed.disqualified,
    reasons: parsed.reasons,
    dataGaps: parsed.dataGaps,
    isHotLead: !parsed.disqualified && score >= threshold,
    scoredAt: new Date().toISOString(),
    config: profile.config
  }
}];
